orders = [
    {"item": "Laptop", "category": "Electronics", "amount": 999},
    {"item": "Shirt", "category": "Clothing", "amount": 49},
    {"item": "Phone", "category": "Electronics", "amount": 699},
    {"item": "Pants", "category": "Clothing", "amount": 79},
    {"item": "Book", "category": "Books", "amount": 29},
    {"item": "Tablet", "category": "Electronics", "amount": 449},
    {"item": "Novel", "category": "Books", "amount": 19},
    {"item": "Jacket", "category": "Clothing", "amount": 129},
]

grouped = {}
for order in orders:
    cat = order["category"]
    if cat not in grouped:
        grouped[cat] = []
    grouped[cat].append(order["amount"])

totals = {cat: sum(amounts) for cat, amounts in grouped.items()}
counts = {cat: len(amounts) for cat, amounts in grouped.items()}

for cat in sorted(totals, key=totals.get, reverse=True):
    print(cat + ": $" + str(totals[cat]) + " (" + str(counts[cat]) + " orders)")
